        "PUT",
        "/channelGroup/$(ChannelGroupName)/channel/$(ChannelName)/originEndpoint/$(OriginEndpointName)",
        Dict{String,Any}("ContainerType" => ContainerType);
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

